#!/usr/bin/env perl
require 5.008;
use warnings;
use strict;

unshift(@INC, '.');
require qpdf_test_helpers;

chdir("qpdf") or die "chdir testdir failed: $!\n";

require TestDriver;

cleanup();

my $td = new TestDriver('completion');

my $n_tests = 2;
$td->runtest("check generated bash completion",
             {$td->COMMAND => "qpdf --completion-bash"},
             {$td->FILE => "../../../completions/bash/qpdf", $td->EXIT_STATUS => 0},
             $td->NORMALIZE_NEWLINES);
$td->runtest("check generated zsh completion",
             {$td->COMMAND => "qpdf --completion-zsh"},
             {$td->FILE => "../../../completions/zsh/_qpdf", $td->EXIT_STATUS => 0},
             $td->NORMALIZE_NEWLINES);


if (system("test_completion >/dev/null 2>&1") == 768) {
    $td->emphasize("completion tests are not supported on this platform");
    $td->report($n_tests);
    exit(0);
}

# installation.rst knows the version numbers checked here
$n_tests += 2;
my $bash_ok = system(
    "bash -c '[ \"\${BASH_VERSINFO[0]}\" -gt 4 ] ||" .
    " { [ \"\${BASH_VERSINFO[0]}\" -eq 4 ] && [ \"\${BASH_VERSINFO[1]}\" -ge 2 ]; }'") == 0;
my $zsh_ok = system("zsh  -c '[[ \${ZSH_VERSION%%.*} -ge 5 ]]'") == 0;

my $action_if_missing = "skip\n";
if (exists $ENV{'REQUIRE_SHELLS'}) {
    $action_if_missing = "fail\n";
}

if ($bash_ok) {
    $td->runtest("bash completion",
                 {$td->COMMAND => "test_completion --shell bash --tests completion-tests"},
                 {$td->STRING => "All tests passed.\n", $td->EXIT_STATUS => 0},
                 $td->NORMALIZE_NEWLINES);
} else {
    $td->emphasize("a new enough bash is not present; skipping bash");
    $td->runtest("skipping bash completion",
                 {$td->STRING => "skip\n"},
                 {$td->STRING => $action_if_missing},
                 $td->NORMALIZE_NEWLINES);
}
if ($zsh_ok) {
    $td->runtest("zsh completion",
                 {$td->COMMAND => "test_completion --shell zsh --tests completion-tests"},
                 {$td->STRING => "All tests passed.\n", $td->EXIT_STATUS => 0},
                 $td->NORMALIZE_NEWLINES);
} else {
    $td->emphasize("a new enough zsh is not present; skipping zsh");
    $td->runtest("skipping zsh completion",
                 {$td->STRING => "skip\n"},
                 {$td->STRING => $action_if_missing},
                 $td->NORMALIZE_NEWLINES);
}

cleanup();
$td->report($n_tests);

